import React, { useState, useRef } from "react"; // NOUVEAU : ajout de useRef
import "./App.css";
import weddingPhoto from "./wedding-photo.jpg";
// NOUVEAU : importation de la musique

function App() {
  const [isOpen, setIsOpen] = useState(false);

  // NOUVEAU : On crée une référence pour contrôler le lecteur audio
  const audioRef = useRef(null);

  // NOUVEAU : La fonction qui ouvre l'enveloppe ET lance la musique
  const handleOpenInvitation = () => {
    setIsOpen(true);
    if (audioRef.current) {
      audioRef.current.play();
    }
  };

  return (
    <div className="app-container">
      {/* NOUVEAU : Le lecteur audio (invisible à l'écran). L'attribut 'loop' permet à la musique de tourner en boucle */}
      <audio ref={audioRef} src={weddingSong} loop />

      {/* ÉTAPE 1 : La lettre d'accueil */}
      {!isOpen ? (
        <div className="page-1-letter" onClick={handleOpenInvitation}>
          <div className="letter-content" onClick={(e) => e.stopPropagation()}>
            <h1 className="names-title">Elyes & Sarra</h1>
            <h2 className="subtitle">We are getting married</h2>
            <button className="open-button" onClick={handleOpenInvitation}>
              Click to open
            </button>
          </div>
        </div>
      ) : (
        /* ÉTAPE 2 : L'annonce avec la photo */
        <div
          className="page-2-details"
          style={{ backgroundImage: `url(${weddingPhoto})` }}
        >
          <div className="overlay">
            <div className="content-wrapper fade-in">
              <p className="location-text">
                Hacienda Event - Bourj Touil | 16h
              </p>

              <div className="elegant-frame">
                <h3 className="save-date">Save Our Day</h3>
                <p className="date">22 Mars 2026</p>
              </div>

              <h1 className="initials">E & S</h1>
              <p className="quote">
                Here's to love, joy and the beginning of our forever!
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
